// Explicit timeouts at every layer. Never rely on defaults.
HttpClient client = HttpClient.newBuilder()
    .connectTimeout(Duration.ofMillis(500))   // TCP connect budget
    .build();

HttpRequest request = HttpRequest.newBuilder()
    .uri(URI.create("https://inventory/api/stock"))
    .timeout(Duration.ofMillis(800))          // whole-request budget
    .GET()
    .build();

// Propagate the remaining budget so downstream hops shrink, not repeat, the timeout.
long deadlineMs = requestStartMs + 3000;
long remaining = deadlineMs - System.currentTimeMillis();
if (remaining <= 0) {
    throw new DeadlineExceededException("budget exhausted before inventory call");
}

// Retry with capped exponential backoff and full jitter.
// Only retry idempotent operations, and only on retryable failures.
int maxAttempts = 4;
long baseMs = 100, capMs = 2000;
for (int attempt = 0; ; attempt++) {
    try {
        return call(); // must be idempotent
    } catch (RetryableException e) {
        if (attempt >= maxAttempts - 1) throw e;
        long exp = Math.min(capMs, baseMs * (1L << attempt));
        long sleep = ThreadLocalRandom.current().nextLong(0, exp + 1); // FULL jitter
        Thread.sleep(sleep);
    } catch (NonRetryableException e) {
        throw e; // 4xx, validation, non-idempotent write => do NOT retry
    }
}

// Resilience4j: declarative circuit breaker + retry + bulkhead stacked.
// Order matters: Retry(Bulkhead(CircuitBreaker(TimeLimiter(call)))).
@CircuitBreaker(name = "inventory", fallbackMethod = "stockFallback")
@Retry(name = "inventory")
@Bulkhead(name = "inventory", type = Bulkhead.Type.THREADPOOL)
public StockLevel getStock(String sku) {
    return inventoryClient.fetch(sku); // remote call
}

// Fallback runs when the breaker is OPEN or the call ultimately fails.
private StockLevel stockFallback(String sku, Throwable t) {
    return StockLevel.unknown(sku); // graceful degradation, not an exception
}

final class CircuitBreaker {
    enum State { CLOSED, OPEN, HALF_OPEN }
    private volatile State state = State.CLOSED;
    private final AtomicInteger failures = new AtomicInteger();
    private volatile long openedAt = 0;
    private final AtomicBoolean probeInFlight = new AtomicBoolean(false);
    private final int threshold; private final long cooldownMs;

    CircuitBreaker(int threshold, long cooldownMs) {
        this.threshold = threshold; this.cooldownMs = cooldownMs;
    }

    <T> T execute(Supplier<T> call) {
        if (state == State.OPEN) {
            if (System.currentTimeMillis() - openedAt < cooldownMs)
                throw new CircuitOpenException(); // fail fast
            state = State.HALF_OPEN;              // cool-down elapsed
        }
        if (state == State.HALF_OPEN && !probeInFlight.compareAndSet(false, true))
            throw new CircuitOpenException();     // only one probe allowed
        try {
            T result = call.get();
            onSuccess();
            return result;
        } catch (RuntimeException e) {
            onFailure();
            throw e;
        } finally {
            if (state == State.HALF_OPEN) probeInFlight.set(false);
        }
    }

    private void onSuccess() {
        failures.set(0);
        state = State.CLOSED;                     // probe succeeded => healed
    }
    private void onFailure() {
        if (state == State.HALF_OPEN || failures.incrementAndGet() >= threshold) {
            state = State.OPEN;                   // trip / re-trip
            openedAt = System.currentTimeMillis();
        }
    }
}

// Semaphore bulkhead: cap concurrency to a single dependency so it can't
// exhaust the shared web-server thread pool.
final class SemaphoreBulkhead {
    private final Semaphore permits;
    SemaphoreBulkhead(int maxConcurrent) { this.permits = new Semaphore(maxConcurrent); }

    <T> T call(Supplier<T> op) {
        if (!permits.tryAcquire()) {
            throw new BulkheadFullException(); // shed load fast, protect the rest
        }
        try {
            return op.get();
        } finally {
            permits.release();
        }
    }
}
// If 'inventory' saturates its 20 permits, 'pricing' and 'recommendations'
// keep their own permits and remain fully available.

// Server-side idempotency: first write wins, retries return the same result.
public OrderResult placeOrder(String idempotencyKey, OrderRequest req) {
    Optional<StoredResult> prior = idempotencyStore.find(idempotencyKey);
    if (prior.isPresent()) {
        return prior.get().asOrderResult(); // safe replay of a retried request
    }
    OrderResult result = orders.create(req); // the real, non-idempotent effect
    idempotencyStore.save(idempotencyKey, result); // dedupe future retries
    return result;
}

