import java.util.function.Supplier;
import java.util.concurrent.atomic.*;

public final class CircuitBreaker {
    public enum State { CLOSED, OPEN, HALF_OPEN }
    public static final class CircuitOpenException extends RuntimeException {}

    private final int failureThreshold;
    private final long cooldownMs;
    private volatile State state = State.CLOSED;
    private volatile long openedAt = 0L;
    private final AtomicInteger consecutiveFailures = new AtomicInteger(0);
    private final AtomicBoolean probeInFlight = new AtomicBoolean(false);

    public CircuitBreaker(int failureThreshold, long cooldownMs) {
        this.failureThreshold = failureThreshold;
        this.cooldownMs = cooldownMs;
    }

    public State state() { return state; }

    public <T> T execute(Supplier<T> call) {
        if (state == State.OPEN) {
            if (System.currentTimeMillis() - openedAt < cooldownMs) {
                throw new CircuitOpenException(); // fail fast
            }
            state = State.HALF_OPEN; // cool-down elapsed, allow probing
        }

        boolean isProbe = false;
        if (state == State.HALF_OPEN) {
            if (!probeInFlight.compareAndSet(false, true)) {
                throw new CircuitOpenException(); // another probe already running
            }
            isProbe = true;
        }

        try {
            T result = call.get();
            onSuccess();
            return result;
        } catch (RuntimeException e) {
            onFailure(isProbe);
            throw e;
        } finally {
            if (isProbe) probeInFlight.set(false);
        }
    }

    private void onSuccess() {
        consecutiveFailures.set(0);
        state = State.CLOSED; // healthy again
    }

    private synchronized void onFailure(boolean wasProbe) {
        if (wasProbe) {
            trip();
            return;
        }
        if (consecutiveFailures.incrementAndGet() >= failureThreshold) {
            trip();
        }
    }

    private void trip() {
        state = State.OPEN;
        openedAt = System.currentTimeMillis();
    }
}

import java.util.concurrent.ThreadLocalRandom;
import java.util.function.Predicate;
import java.util.function.Supplier;

public final class Retrier {
    private final int maxAttempts;
    private final long baseMs;
    private final long capMs;
    private final Predicate<RuntimeException> isRetryable;

    public Retrier(int maxAttempts, long baseMs, long capMs,
                   Predicate<RuntimeException> isRetryable) {
        this.maxAttempts = maxAttempts;
        this.baseMs = baseMs;
        this.capMs = capMs;
        this.isRetryable = isRetryable;
    }

    /** @param idempotent whether re-executing the op is safe (key present or naturally idempotent). */
    public <T> T call(Supplier<T> op, boolean idempotent, long deadlineMs) {
        RuntimeException last = null;
        for (int attempt = 0; attempt < maxAttempts; attempt++) {
            try {
                return op.get();
            } catch (RuntimeException e) {
                last = e;
                boolean canRetry = isRetryable.test(e) && idempotent;
                if (!canRetry || attempt == maxAttempts - 1) {
                    throw e; // non-retryable, unsafe to retry, or attempts exhausted
                }
                long now = System.currentTimeMillis();
                long remaining = deadlineMs - now;
                if (remaining <= 0) throw e; // budget exhausted

                long expWindow = Math.min(capMs, baseMs * (1L << attempt)); // capped exp
                long jittered = ThreadLocalRandom.current().nextLong(0, expWindow + 1); // FULL jitter
                long sleep = Math.min(jittered, remaining); // never overshoot deadline
                try {
                    Thread.sleep(sleep);
                } catch (InterruptedException ie) {
                    Thread.currentThread().interrupt();
                    throw e;
                }
            }
        }
        throw last; // unreachable in practice, but keeps the compiler happy
    }
}
